                            {
                                var renderStaff: com.omnifret.gplayer.rendering.staves.RenderStaff = com.omnifret.gplayer.rendering.staves.RenderStaff(system, trackIndex, staff, factory)
                                renderStaff.topEffectInfos.splice(0.0, 0.0, *sharedTopEffects.spread())
